using Microsoft.EntityFrameworkCore;
using NetDwhProject.Core.DwEntities;
using NetDwhProject.Core.Entities;
namespace NetDwhProject.Infrastructure;
public class OltpDbContext:DbContext{public OltpDbContext(DbContextOptions<OltpDbContext> o):base(o){}public DbSet<User> Users=>Set<User>();public DbSet<Role> Roles=>Set<Role>();public DbSet<UserRole> UserRoles=>Set<UserRole>();public DbSet<Category> Categories=>Set<Category>();public DbSet<SubCategory> SubCategories=>Set<SubCategory>();public DbSet<Product> Products=>Set<Product>();public DbSet<Order> Orders=>Set<Order>();public DbSet<OrderItem> OrderItems=>Set<OrderItem>();protected override void OnModelCreating(ModelBuilder b){b.Entity<User>().HasIndex(x=>x.Username).IsUnique();b.Entity<Role>().HasIndex(x=>x.Name).IsUnique();b.Entity<UserRole>().HasKey(x=>new{x.UserId,x.RoleId});b.Entity<Category>().HasIndex(x=>x.Name).IsUnique();b.Entity<SubCategory>().HasIndex(x=>new{x.CategoryId,x.Name}).IsUnique();b.Entity<Product>().Property(x=>x.Price).HasPrecision(18,2);b.Entity<Order>().HasIndex(x=>x.OrderNumber).IsUnique();b.Entity<Order>().Property(x=>x.SubTotal).HasPrecision(18,2);b.Entity<Order>().Property(x=>x.Tax).HasPrecision(18,2);b.Entity<Order>().Property(x=>x.Shipping).HasPrecision(18,2);b.Entity<Order>().Property(x=>x.Total).HasPrecision(18,2);b.Entity<OrderItem>().Property(x=>x.UnitPrice).HasPrecision(18,2);b.Entity<OrderItem>().Property(x=>x.LineTotal).HasPrecision(18,2);}}
public class DwDbContext:DbContext{public DwDbContext(DbContextOptions<DwDbContext> o):base(o){}public DbSet<Currency> Currency=>Set<Currency>();public DbSet<Customer> Customer=>Set<Customer>();public DbSet<ProductDw> Products=>Set<ProductDw>();public DbSet<Sales> Sales=>Set<Sales>();public DbSet<SalesPerson> SalesPerson=>Set<SalesPerson>();public DbSet<ShipMethod> ShipMethod=>Set<ShipMethod>();public DbSet<Territory> Territory=>Set<Territory>();protected override void OnModelCreating(ModelBuilder b){b.Entity<ProductDw>().ToTable("Products").HasKey(x=>x.ProductKey);b.Entity<ProductDw>().Property(x=>x.StandardCost).HasPrecision(19,4);b.Entity<Sales>().ToTable("Sales").HasKey(x=>x.SalesKey);b.Entity<Sales>().Property(x=>x.UnitPrice).HasPrecision(19,4);b.Entity<Sales>().Property(x=>x.LineTotal).HasPrecision(38,6);b.Entity<Currency>().ToTable("Currency").HasKey(x=>x.CurrencyKey);b.Entity<Customer>().ToTable("Customer").HasKey(x=>x.CustomerKey);b.Entity<SalesPerson>().ToTable("SalesPerson").HasKey(x=>x.EmployeeKey);b.Entity<SalesPerson>().Property(x=>x.SalesQuota).HasPrecision(19,4);b.Entity<ShipMethod>().ToTable("ShipMethod").HasKey(x=>x.ShipMethodID);b.Entity<Territory>().ToTable("Territory").HasKey(x=>x.SalesTerritoryKey);}}
